sql:
SELECT variant_name
FROM game_variants
WHERE download_count = (SELECT MAX(download_count) FROM game_variants);

external_knowledge:
; Game variants refer to different versions or modes of the game; 
; Roles in this context may include 'admin', 'player', etc.; 
; Actions taken by admins can include 'ban', 'kick', 'warn', etc.

sql:
SELECT variant_name
FROM game_variants
WHERE rating > 4.0;

SELECT COUNT(*) AS total_deaths
FROM death_logs
WHERE killer = 'goblin';

SELECT variant_name, download_count
FROM game_variants
ORDER BY download_count DESC;
